import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"长廊","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/changlang.md","filePath":"landmarks/summer-palace/changlang.md","lastUpdated":1784720050000}'),o={name:"landmarks/summer-palace/changlang.md"};function n(i,t,s,d,g,h){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="长廊" tabindex="-1">长廊 <a class="header-anchor" href="#长廊" aria-label="Permalink to &quot;长廊&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1645526629357-16bbd762c8d5?w=1200&amp;q=80" alt="长廊"></p><blockquote><p>&quot;一步一景，一画一世界。&quot; —— 世界上最长的画廊，七百二十八米的丹青长卷</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>长廊东起邀月门，西至石丈亭，沿昆明湖北岸蜿蜒逶迤，全长728米，共273间，是中国古典园林中最长的游廊，被载入吉尼斯世界纪录，誉为&quot;世界第一长廊&quot;。</p><p>它像一条彩带，将万寿山前的<a href="/beijing-travel-guide/landmarks/summer-palace/paiyun-dian.html">排云殿</a>、<a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a>、乐寿堂、听鹂馆等景点串珠成链。游人循廊而行，晴不知日，雨不湿衣，山色湖光在廊柱间次第展开。</p><p>长廊始建于乾隆十五年（1750年）。咸丰十年（1860年）遭英法联军焚毁，现存建筑为光绪年间重建，廊内彩画亦为彼时重绘。1992年，长廊以&quot;世界上最长的游廊&quot;之姿被吉尼斯世界纪录收录，成为中国园林向世界递出的第一张名片。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清乾隆十五年（1750）</td><td style="text-align:left;">随清漪园始建，为皇太后雨雪天气游湖而设</td></tr><tr><td style="text-align:left;">咸丰十年（1860）</td><td style="text-align:left;">遭英法联军焚毁</td></tr><tr><td style="text-align:left;">清光绪年间</td><td style="text-align:left;">重建，廊内重绘苏式彩画</td></tr><tr><td style="text-align:left;">1959年</td><td style="text-align:left;">迎国庆组织画师按光绪旧制大规模重绘彩画</td></tr><tr><td style="text-align:left;">1992年</td><td style="text-align:left;">被认定为&quot;世界最长游廊&quot;，载入吉尼斯世界纪录</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全长</strong></td><td style="text-align:left;">728米，共273间</td></tr><tr><td style="text-align:left;"><strong>彩画数量</strong></td><td style="text-align:left;">14000余幅苏式彩画，无一雷同</td></tr><tr><td style="text-align:left;"><strong>四季亭</strong></td><td style="text-align:left;">留佳（春）、寄澜（夏）、秋水（秋）、清遥（冬）四座八角亭</td></tr><tr><td style="text-align:left;"><strong>附属建筑</strong></td><td style="text-align:left;">对鸥舫、鱼藻轩两座临湖水榭</td></tr><tr><td style="text-align:left;"><strong>整体形态</strong></td><td style="text-align:left;">随湖岸曲折，俯瞰如展翅之蝠，&quot;蝠&quot;谐&quot;福&quot;</td></tr></tbody></table><p>长廊并非笔直，而是随湖岸曲折，中部以排云门为界向两翼展开。廊中每隔一段便有一座八角亭歇脚，其中留佳、寄澜、秋水、清遥四亭分别象征春夏秋冬四时，亭名皆取自诗文，意趣隽永。</p><p>廊内梁枋之上，14000余幅苏式彩画题材大致可分四类：</p><table tabindex="0"><thead><tr><th style="text-align:left;">彩画类别</th><th style="text-align:left;">内容举例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>山水</strong></td><td style="text-align:left;">西湖十景、江南风光，底本多出自乾隆南巡画师写生</td></tr><tr><td style="text-align:left;"><strong>人物故事</strong></td><td style="text-align:left;">《西游记》《三国演义》《水浒传》《红楼梦》《聊斋》等</td></tr><tr><td style="text-align:left;"><strong>花鸟鱼虫</strong></td><td style="text-align:left;">四季花卉、翎毛草虫，工写兼备</td></tr><tr><td style="text-align:left;"><strong>博古纹样</strong></td><td style="text-align:left;">器物、几何图案，点缀于枋心箍头之间</td></tr></tbody></table><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="为母筑廊的孝心" tabindex="-1">为母筑廊的孝心 <a class="header-anchor" href="#为母筑廊的孝心" aria-label="Permalink to &quot;为母筑廊的孝心&quot;">​</a></h3><p>乾隆十六年是崇庆皇太后的六十大寿。乾隆知道母亲最爱西湖山水，又怕北方风寒伤身，便下令沿昆明湖北岸修建长廊，让太后&quot;不出宫门而览尽江南&quot;。此后每逢雨雪，太后便由宫女搀扶漫步廊中，看廊外湖山烟雨，听檐下风铃叮咚。这条长廊因此又被称为&quot;孝廊&quot;——帝王家的奢华背后，也有一份寻常的母子之情。</p><h3 id="一万四千幅画-没有一幅重样" tabindex="-1">一万四千幅画，没有一幅重样 <a class="header-anchor" href="#一万四千幅画-没有一幅重样" aria-label="Permalink to &quot;一万四千幅画，没有一幅重样&quot;">​</a></h3><p>光绪年间重绘长廊彩画时，朝廷从江南请来大批画师，限期完工。画师们以《芥子园画谱》为底本，博采历代名画粉本，山水取法西湖十景，人物囊括四大名著与民间传说。最难的是&quot;无一雷同&quot;——273间廊段，每一间的包袱画都需另起炉灶。据传验收时慈禧逐幅过目，稍有重复或败笔即令重绘，最终成就这座&quot;走不完的画廊&quot;。如今游人见到的彩画，大部分为1959年迎国庆时由京津画师按光绪旧制再次重绘，笔法虽新，格局依旧。</p><h3 id="蝙蝠廊里藏-福-字" tabindex="-1">蝙蝠廊里藏&quot;福&quot;字 <a class="header-anchor" href="#蝙蝠廊里藏-福-字" aria-label="Permalink to &quot;蝙蝠廊里藏&quot;福&quot;字&quot;">​</a></h3><p>从空中俯瞰，长廊以排云门为中心向东西两翼伸展，中部微微向南凸出，整体恰似一只展翅的蝙蝠。&quot;蝠&quot;与&quot;福&quot;同音，蝙蝠纹本就是清宫最常见的吉祥图案。乾隆以&quot;蝠形&quot;布廊，等于在昆明湖畔画了一个巨大的&quot;福&quot;字，把对太后的祝寿之意藏进了平面布局里——造园家的心思，要飞起来才看得见。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>万幅彩画</strong>：边走边找《西游记》《三国演义》故事画，是老少咸宜的&quot;寻宝游戏&quot;，人物画多集中于廊内侧梁枋。</li><li><strong>四季亭</strong>：留意留佳、寄澜、秋水、清遥四座八角亭的匾额与位置，体会造园家以亭点景、以名寄时的巧思。</li><li><strong>框景成画</strong>：廊柱与横枋天然构成画框，昆明湖、南湖岛、十七孔桥皆入画中，随手一拍即是明信片。</li><li><strong>对鸥舫与鱼藻轩</strong>：廊中部伸向湖面的两座水榭，是凭栏观湖、喂鱼赏荷的最佳处。</li><li><strong>听鹂馆</strong>：廊西侧的皇家戏台旧址，如今是著名的宫廷菜餐厅，逛累了可在此歇脚。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>廊内透视</strong>：站在廊中央，利用立柱与彩绘的重复韵律拍纵深，广角镜头效果极佳。</li><li><strong>框景构图</strong>：以廊柱为框拍昆明湖与十七孔桥，&quot;画中游&quot;变成&quot;画外看画&quot;。</li><li><strong>彩画特写</strong>：侧光时段（清晨或傍晚）拍梁枋包袱画，色彩最饱和。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>长廊全天开放、无需额外购票，但旺季人潮汹涌，想拍空镜务必赶早（开园后一小时内）或傍晚。</li><li>建议自东向西走（邀月门→石丈亭方向），顺光看彩画，且越走越接近<a href="/beijing-travel-guide/landmarks/summer-palace/shifang.html">石舫</a>和画中游。</li><li>细看彩画需仰头，颈椎不佳者量力而行；重点欣赏排云门两侧的&quot;包袱画&quot;精华段即可。</li><li>廊内禁止倚坐栏杆、攀爬彩绘，苏式彩画怕汗怕蹭，人人爱护才能长久。</li><li>长廊与<a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a>中轴线十字相交，逛完长廊正好从排云门拾级登山，动线无缝衔接。</li><li>带本《西游记》或《三国》故事清单来&quot;按图索骥&quot;，比走马观花有趣十倍。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：长廊的彩画都是光绪年间的原作吗？</strong></p><p>不全是。光绪年间重绘后，1959年迎国庆又由京津画师按光绪旧制大规模重绘，如今所见大部分为彼时手笔，格局一仍其旧。</p><p><strong>Q：走完长廊需要多久？</strong></p><p>长廊全长728米，正常步速15-20分钟可走完；若逐间看彩画、亭中歇脚，建议留足40-60分钟。</p><p><strong>Q：雨天逛长廊体验如何？</strong></p><p>极佳。长廊本就是为雨雪天游湖而建，雨打湖面、廊外烟水朦胧，而廊内片雨不沾——这是颐和园最地道的&quot;隐藏玩法&quot;。</p><p><strong>Q：长廊适合老人小孩吗？</strong></p><p>非常适合。全程平路无坡，每隔数十米就有八角亭歇脚，是颐和园无障碍程度最高的路线之一。</p><hr><p><strong>📍 位置</strong>：万寿山南麓，昆明湖北岸，东起邀月门西至石丈亭 <strong>⏱️ 建议游览</strong>：40-60分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',38)])])}const p=e(o,[["render",n]]);export{q as __pageData,p as default};
